at::Tensor matmul_mish_mish_impl_npu(const at::Tensor& x,
                                     const at::Tensor& weight,
                                     const at::Tensor& bias) {
    TORCH_CHECK(x.dim() == 2, \"x must be 2D [B, K]\");
    TORCH_CHECK(weight.dim() == 2, \"weight must be 2D [N, K]\");
    TORCH_CHECK(bias.dim() == 1, \"bias must be 1D [N]\");
    TORCH_CHECK(x.size(1) == weight.size(1), \"K mismatch\");
    TORCH_CHECK(weight.size(0) == bias.size(0), \"N mismatch\");

    at::Tensor y = at::empty({x.size(0), weight.size(0)}, x.options());
    EXEC_NPU_CMD(aclnnMatmulMishMishCustom, x, weight, bias, y);
    return y;
}

